{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [{
          "name": "TimeRange",
          "type": 4,
          "value": { "durationMs": 604800000 }
        }]
      }
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "SignInLogs | where TimeGenerated {TimeRange} | summarize Count=count() by ResultType",
        "visualization": "piechart",
        "title": "Sign-In Results"
      }
    }
  ]
}

# Run a workbook-equivalent KQL query on a schedule and email results
# Uses Logic App + Log Analytics action (no native email in workbooks)

# Deploy Logic App via az CLI (simplified — use ARM for production)
$body = @{
    definition = @{
        triggers = @{
            recurrence = @{ type = "Recurrence"; recurrence = @{ frequency = "Week"; interval = 1 } }
        }
        actions = @{
            runKQL = @{
                type = "ApiConnection"
                inputs = @{
                    host = @{ connection = @{ name = "@parameters('$connections')['azureloganalyticsdatacollector']['connectionId']" } }
                    method = "post"
                    path = "/workspaces/<law-id>/query"
                    body = "SignInLogs | where TimeGenerated > ago(7d) | where RiskLevelDuringSignIn in ('medium','high') | take 100"
                }
            }
        }
    }
} | ConvertTo-Json -Depth 20
Write-Host 'Deploy this definition via portal or ARM template for production use'
